template <typename T>
T clamp_generic(T x, T lo, T hi){
    if (x < lo) return lo;
    if (x > hi) return hi;
    return x;
}

mojo_unit:
def clamp_generic[T: Comparable & ImplicitlyCopyable](x: T, lo: T, hi: T) -> T:
    if x < lo:
        return lo
    if x > hi:
        return hi
    return x

cpp_driver:
int main(){
    printf("%d\n", clamp_generic<int>(5, 0, 10));
    printf("%d\n", clamp_generic<int>(-3, 0, 10));
    printf("%d\n", clamp_generic<int>(42, 0, 10));
    printf("%.6g\n", clamp_generic<double>(2.5, 1.0, 2.0));
    printf("%.6g\n", clamp_generic<double>(0.5, 1.0, 2.0));
    return 0;
}

