template <typename T>
struct Pair {
    T first;
    T second;
    Pair(T a, T b) : first(a), second(b) {}
    Pair<T> swapped() const { return Pair<T>(second, first); }
};

mojo_unit:
@fieldwise_init
struct Pair[T: ImplicitlyCopyable & Movable](Copyable, Movable):
    var first: Self.T
    var second: Self.T

    def swapped(self) -> Pair[Self.T]:
        return Pair[Self.T](self.second, self.first)

