template <typename T>
T max_of_three(T a, T b, T c){
    T m = a;
    if (b > m) m = b;
    if (c > m) m = c;
    return m;
}

mojo_unit:
def max_of_three[T: Comparable & ImplicitlyCopyable](a: T, b: T, c: T) -> T:
    var m = a
    if b > m:
        m = b
    if c > m:
        m = c
    return m

